import os
from flask import Flask, session, request, redirect, url_for, render_template, flash
from onelogin.saml2.auth import OneLogin_Saml2_Auth
from onelogin.saml2.settings import OneLogin_Saml2_Settings
from onelogin.saml2.utils import OneLogin_Saml2_Utils
import json

app = Flask(__name__)
app.secret_key = os.urandom(24)  # A strong secret key for session management

# Configuration files
SAML_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'saml')
SETTINGS_FILE = os.path.join(SAML_PATH, 'settings.json')
ADV_SETTINGS_FILE = os.path.join(SAML_PATH, 'advanced_settings.json')

def init_saml_auth(req):
    """
    Initializes the SAML authentication object.
    Loads settings from settings.json and advanced_settings.json,
    and dynamically updates SP URLs and loads SP certificates.
    """
    settings = None
    if os.path.exists(SETTINGS_FILE):
        with open(SETTINGS_FILE, 'r') as f:
            settings = json.load(f)

    if settings is None:
        raise Exception("SAML settings.json not found or invalid.")

    # Load advanced settings if they exist and merge
    if os.path.exists(ADV_SETTINGS_FILE):
        with open(ADV_SETTINGS_FILE, 'r') as f:
            advanced_settings = json.load(f)
            # Merge advanced settings into main settings, handling nested dictionaries
            for key, value in advanced_settings.items():
                if key in settings and isinstance(settings[key], dict) and isinstance(value, dict):
                    settings[key].update(value)
                else:
                    settings[key] = value

    # Dynamically update SP URLs based on the current request
    base_url = OneLogin_Saml2_Utils.get_self_url(req)
    if 'sp' in settings and 'assertionConsumerService' in settings['sp']:
        settings['sp']['assertionConsumerService']['url'] = base_url + url_for('acs')
    if 'sp' in settings and 'singleLogoutService' in settings['sp']:
        settings['sp']['singleLogoutService']['url'] = base_url + url_for('sls')
    if 'sp' in settings:
        # Entity ID often matches metadata URL, but can be separate
        # Update if it contains a placeholder or needs dynamic adjustment
        if settings['sp']['entityId'].endswith('/saml/metadata'):
            settings['sp']['entityId'] = base_url + url_for('saml_metadata')


    # Load SP certificates and private key from files
    # The settings.json should store filenames, and we read the content here
    sp_cert_file = settings.get('sp', {}).get('x509cert')
    if sp_cert_file and os.path.exists(os.path.join(SAML_PATH, 'certs', sp_cert_file)):
        with open(os.path.join(SAML_PATH, 'certs', sp_cert_file), 'r') as f:
            settings['sp']['x509cert'] = f.read()
    else:
        # If cert file not found, ensure the field is empty to avoid errors
        settings['sp']['x509cert'] = ''
        if sp_cert_file: # Only warn if a filename was specified
            print(f"WARNING: SP certificate file not found: {os.path.join(SAML_PATH, 'certs', sp_cert_file)}")

    sp_key_file = settings.get('sp', {}).get('privateKey')
    if sp_key_file and os.path.exists(os.path.join(SAML_PATH, 'certs', sp_key_file)):
        with open(os.path.join(SAML_PATH, 'certs', sp_key_file), 'r') as f:
            settings['sp']['privateKey'] = f.read()
    else:
        # If key file not found, ensure the field is empty
        settings['sp']['privateKey'] = ''
        if sp_key_file: # Only warn if a filename was specified
            print(f"WARNING: SP private key file not found: {os.path.join(SAML_PATH, 'certs', sp_key_file)}")

    auth = OneLogin_Saml2_Auth(req, settings)
    return auth

def prepare_flask_request(request):
    """
    Prepares the Flask request object into a dictionary format
    expected by python3-saml library.
    """
    url_data = OneLogin_Saml2_Utils.get_self_url_no_query(request)
    return {
        'https': 'on' if request.scheme == 'https' else 'off',
        'http_host': request.host,
        'server_port': request.port,
        'script_name': request.path,
        'get_data': request.args.copy(),
        'post_data': request.form.copy(),
        'query_string': request.query_string.decode('utf-8'),
        'url': url_data
    }

@app.route('/')
def index():
    if 'samlUserdata' in session:
        return render_template('dashboard.html', samlUserdata=session['samlUserdata'], name_id=session['samlNameId'])
    return render_template('index.html')

@app.route('/login')
def login():
    """
    Initiates an SP-initiated SSO flow by generating a SAML AuthNRequest
    and redirecting the user to the IdP's SSO endpoint.
    """
    req = prepare_flask_request(request)
    auth = init_saml_auth(req)
    return redirect(auth.login())

@app.route('/saml/acs', methods=['POST'])
def acs():
    """
    Assertion Consumer Service endpoint.
    Receives the SAML Response from the IdP, validates it, and authenticates the user.
    """
    req = prepare_flask_request(request)
    auth = init_saml_auth(req)

    # Process the SAML Response.
    # This method performs all necessary validations:
    # - XML parsing and schema validation.
    # - Signature presence and validity (against the IdP's certificate).
    # - Audience restriction.
    # - NotBefore/NotOnOrAfter validity periods.
    # - InResponseTo (if an AuthNRequest was sent).
    # - Status code success.
    # - Recipient check.
    # The default behavior ensures signature is checked if 'wantMessagesSigned'
    # or 'wantAssertionsSigned' is true in settings.
    auth.process_response()

    errors = auth.get_errors()
    if errors:
        print(f"SAML Errors: {errors}")
        flash(f"SAML processing errors: {auth.get_last_error_reason()}", 'danger')
        return render_template('error.html', errors=errors, reason=auth.get_last_error_reason())

    if not auth.is_authenticated():
        flash("SAML authentication failed.", 'danger')
        return render_template('error.html', errors=["Authentication failed"], reason="User not authenticated by SAML Response.")

    # User is authenticated, extract data and store in session
    session['samlUserdata'] = auth.get_attributes()
    session['samlNameId'] = auth.get_nameid()
    session['samlNameIdFormat'] = auth.get_nameid_format()
    session['samlSessionIndex'] = auth.get_session_index()

    flash("Successfully logged in via SAML!", 'success')
    # If a RelayState was provided, redirect to it; otherwise, go to the index
    relay_state = req['post_data'].get('RelayState', url_for('index'))
    return redirect(relay_state)

@app.route('/logout')
def logout():
    """
    Performs a local logout.
    For a full SAML Single Logout (SLO) flow, this would initiate an SLO request to the IdP.
    """
    session.pop('samlUserdata', None)
    session.pop('samlNameId', None)
    session.pop('samlNameIdFormat', None)
    session.pop('samlSessionIndex', None)
    flash("You have been logged out.", 'info')
    return redirect(url_for('index'))

