@app.route('/saml/metadata')
def saml_metadata():
    """
    Generates and serves the SP's SAML metadata XML.
    This metadata should be provided to the Identity Provider.
    """
    req = prepare_flask_request(request)
    auth = init_saml_auth(req)
    settings = auth.get_settings()

    metadata = settings.get_sp_metadata()
    errors = settings.validate_metadata(metadata)

    if errors:
        print(f"Metadata errors: {errors}")
        flash(f"Error generating metadata: {', '.join(errors)}", 'danger')
        return render_template('error.html', errors=errors, reason="Error generating SP metadata.")

    response = app.make_response(metadata)
    response.headers['Content-Type'] = 'text/xml'
    return response

